SELECT stores.stor_id, stores.stor_name, stores.city, stores.state, titles.title_id, titles.title, titles.price, sales.qty, roysched.royalty, (titles.price * sales.qty * roysched.royalty / 100) AS author_revenue, publishers.pub_id, publishers.pub_name FROM stores JOIN sales ON stores.stor_id = sales.stor_id JOIN titles ON sales.title_id = titles.title_id JOIN roysched ON titles.title_id = roysched.title_id JOIN publishers ON titles.pub_id = publishers.pub_id WHERE (publishers.pub_id = '1389') AND (stores.state = 'CA')
